  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 58, '다음은 무엇에 대한 글인지 고르십시오.', 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-41/reading/q58.png', NULL, NULL, '["사원모집", "여행소개", "제품설명", "판매안내"]'::jsonb, 2, '사원모집', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 59, '다음 글 또는 도표의 내용과 같은 것을 고르십시오.', 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-41/reading/q59.png', NULL, NULL, '["동아리지원은일년동안계속된다.", "동아리는고등학생들로만구성되어야한다.", "동아리활동비는이백만원까지받을수있다.", "동아리인원이두세명인경우에도신청할수있다."]'::jsonb, 2, '동아리활동비는이백만원까지받을수있다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 60, '다음 글 또는 도표의 내용과 같은 것을 고르십시오.', 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-41/reading/q60.png', NULL, NULL, '["식료품구입이2013년보다늘었다.", "가방류판매가2013년에비해줄었다.", "두해모두화장품이가장많이판매되었다.", "2014년에는의류가먹을것보다많이팔렸다."]'::jsonb, 2, '두해모두화장품이가장많이판매되었다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 61, '최근초록콩나물을찾는주부들이늘고있다.노란콩나물은보통검은색천으로덮어어두운곳에서기른다.그러나초록콩나물은천으로가리지않고밝은곳에서자라게한다.햇빛을받아초록색으로변한콩나물은노란콩나물보다영양가가높다.특히초록콩나물은노란콩나물보다비타민이많이들어있어서피로회복에좋다.', NULL, NULL, NULL, '["노란콩나물은햇빛을받고자란다.", "초록콩나물은검은색천을덮어서키운다.", "노란콩나물은초록콩나물보다피로회복에좋다.", "초록콩나물은노란콩나물에비해영양가가많다."]'::jsonb, 2, '초록콩나물은노란콩나물에비해영양가가많다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 62, '손을움직이는것은뇌와관련이있다.그래서손을자주움직이면뇌기능이좋아질수있다.특히자주사용하지않는손을움직일때뇌가더효과적으로자극될수있다.평소에오른손을많이쓴다면왼손을,왼손을많이쓴다면오른손을사용하는것이다.문을열고닫는일처럼간단한일을그렇게하는것만으로도뇌기능을유지하는데도움이된다.', NULL, NULL, NULL, '["뇌건강과손을움직이는것은서로관계가없다.", "우리몸과달리뇌는간단한일로자극받지않는다.", "뇌활동을위해익숙한방법으로손을쓰는것이더좋다.", "자주사용하지않던손을사용하면뇌움직임이활발해진다."]'::jsonb, 2, '자주사용하지않던손을사용하면뇌움직임이활발해진다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 63, '(가)이것으로만든차는여름철에마시면특히좋다.(나)오미자는다섯가지맛이난다고붙여진이름이다.(다)땀이나지않게하고배탈을낫게하는효과가있어서이다.(라)또한무더위에지친사람에게입맛이나게하는데도도움이된다.', NULL, NULL, NULL, '["(가)－(라)－(다)－(나)", "(가)－(다)－(라)－(나)", "(나)－(가)－(다)－(라)", "(나)－(다)－(가)－(라)"]'::jsonb, 2, '(나)－(가)－(다)－(라)', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 64, '(가)이런행복을느낄때도있지만가끔힘들고어려울때도있다.(나)하지만나는그들을가르칠때마다내가국가대표라고생각한다.(다)한국어로다른문화권의학생들과교류하는것은참행복한일이다.(라)나는그들을통해세상을보고그들은나를통해한국을보기때문이다.', NULL, NULL, NULL, '["(다)－(가)－(나)－(라)", "(다)－(나)－(가)－(라)", "(라)－(가)－(다)－(나)", "(라)－(다)－(가)－(나)"]'::jsonb, 2, '(다)－(가)－(나)－(라)', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 65, '(가)정부에건의할내용이있을때이곳을활용할수있다.(나)오늘날에는‘인터넷신문고’가이러한역할을하고있다.(다)과거에는‘신문고’라는북을설치해서국민의생각을들었다.(라)이렇게시대는달라져도국가가국민의생각을들으려는노력은계속된다.', NULL, NULL, NULL, '["(나)－(다)－(가)－(라)", "(나)－(라)－(다)－(가)", "(다)－(나)－(가)－(라)", "(다)－(라)－(나)－(가)"]'::jsonb, 2, '(다)－(나)－(가)－(라)', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 66, '막대에학생들의이름을써서통에꽂아놓고하나씩뽑아서발표를시키는수업방식이있다.이것은()방식이다.적극적인학생들이먼저손을들고질문에대답하면소극적인학생들이대답할기회를놓치게된다.이방식은모든학습자들에게골고루수업에참여할수있게한다는긍정적인면이있다.', NULL, NULL, NULL, '["학생들의이름을빨리기억하기위한", "수업의단계를동일하게맞추기위한", "수업의진행을좀더부드럽게하기위한", "적극성이떨어지는학생에게도기회를주기위한"]'::jsonb, 2, '적극성이떨어지는학생에게도기회를주기위한', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 67, '어렸을때부터전자기기에능숙한청소년들을가리켜‘디지털원어민’이라부른다.이들은하루의대부분을전자기기를사용하는데쓰며인터넷가상공간에서정보를얻거나다른사람과의관계를형성하는데시간을보낸다.또한이들은유행에뒤떨어지는것을두려워한다.그래서()못할경우에불안해하기도한다.', NULL, NULL, NULL, '["부모의관심을받지", "학업성적이오르지", "모르는사람의정보를얻지", "새로출시된신제품을사지"]'::jsonb, 2, '새로출시된신제품을사지', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 68, '동양에서는우리몸에흐르는에너지를‘기’라고한다.한의학에서는기가잘흐르는사람을건강한사람으로생각한다.그리고기가잘흐르지않거나막혀있는사람은병에걸리기쉽다고한다.기가막혀병에걸린사람들을한의학에서는바늘처럼생긴침을이용하여치료한다.침은기가막힌곳을자극해()한다.', NULL, NULL, NULL, '["기의흐름을원활하게", "기의방향을확인하게", "환자의질병을예방하게", "환자의통증을진단하게"]'::jsonb, 2, '기의흐름을원활하게', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 69, '()에들어갈알맞은것을고르십시오.', NULL, NULL, NULL, '["특히", "또는", "역시", "과연"]'::jsonb, 2, '특히', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 70, '이글의내용과같은것을고르십시오.', NULL, NULL, NULL, '["활쏘기로판단력을높일수있다.", "활쏘기의핵심은숨을참는것이다.", "활쏘기로참을성을기르기가어렵다.", "활쏘기는단순한운동이라주목을받았다."]'::jsonb, 2, '활쏘기로판단력을높일수있다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 71, '최근한할아버지가거리를청소하면서모은돈100여만원을장학금으로내놓았다.()이라고지난5년동안바닥에버려진10원짜리동전을하나하나씩주워모은것이다.사람들은큰돈이있어야만다른사람을도와줄수있다고생각한다.하지만참된기부란돈의액수가중요한것이아니라다른사람을향한사랑의마음이다.
()에들어갈알맞은것을고르십시오.', NULL, NULL, NULL, '["제눈의안경", "엎질러진물", "싼게비지떡", "티끌모아태산"]'::jsonb, 2, '티끌모아태산', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 72, '최근한할아버지가거리를청소하면서모은돈100여만원을장학금으로내놓았다.()이라고지난5년동안바닥에버려진10원짜리동전을하나하나씩주워모은것이다.사람들은큰돈이있어야만다른사람을도와줄수있다고생각한다.하지만참된기부란돈의액수가중요한것이아니라다른사람을향한사랑의마음이다.
이글의중심생각을고르십시오.', NULL, NULL, NULL, '["생활속에서동전의활용성을높여야한다.", "다른사람을도와주려면큰돈을모아야한다.", "참된기부는자신보다남을먼저생각해야한다.", "큰돈을모으려면아끼고절약하는습관을길러야한다."]'::jsonb, 2, '참된기부는자신보다남을먼저생각해야한다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 73, '할머니를시골에두고혼자서울로올라오는발걸음은가볍지않았다.하지만무거웠던마음은며칠가지않았다.할머니는날마다전화를하더니급기야서울로올라오시고말았다.할머니의손자사랑은어쩔수없나보다.할머니는청소며빨래며나에게는안보이던온갖집안일들을찾아서하기시작했다.그냥쉬다가내려가시라고아무리말해도들은척도하지않았다.서른이넘은나는할머니가보기엔여전히아이에불과했다.서울살이몇주만에낯선동네에서친구까지사귄할머니는친구를따라시장에갔다가넘어지시고말았다.병원에서온연락을받고걱정이되어정신없이달려갔더니할머니는같은병실사람들을모아놓고환하게웃으며이야기하고있었다.다리에붕대를감고서말이다.그광경을보고난할말을잃었다.
밑줄부분에나타난나의심정으로알맞은것을고르십시오.', NULL, NULL, NULL, '["답답하다", "후련하다", "민망하다", "번거롭다"]'::jsonb, 2, '답답하다', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 74, '할머니를시골에두고혼자서울로올라오는발걸음은가볍지않았다.하지만무거웠던마음은며칠가지않았다.할머니는날마다전화를하더니급기야서울로올라오시고말았다.할머니의손자사랑은어쩔수없나보다.할머니는청소며빨래며나에게는안보이던온갖집안일들을찾아서하기시작했다.그냥쉬다가내려가시라고아무리말해도들은척도하지않았다.서른이넘은나는할머니가보기엔여전히아이에불과했다.서울살이몇주만에낯선동네에서친구까지사귄할머니는친구를따라시장에갔다가넘어지시고말았다.병원에서온연락을받고걱정이되어정신없이달려갔더니할머니는같은병실사람들을모아놓고환하게웃으며이야기하고있었다.다리에붕대를감고서말이다.그광경을보고난할말을잃었다.
이글의내용과같은것을고르십시오.', NULL, NULL, NULL, '["할머니께서는내말에자주귀를기울이셨다.", "할머니께서는시장에갔다가다리를다치셨다.", "할머니께서는나에게온갖집안일을시키셨다.", "할머니께서는친구를만나려고서울에올라오셨다."]'::jsonb, 2, '할머니께서는시장에갔다가다리를다치셨다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 75, '낮에는화창,밤부터곳에따라빗방울‘뚝뚝’', NULL, NULL, NULL, '["낮에는흐리고밤부터전국에비가내리겠다.", "낮에는맑겠으나밤부터전국에비가내리겠다.", "낮에는맑겠으나밤부터일부지역에는비가오겠다.", "낮에는흐리고밤부터일부지역에는비가쏟아지겠다."]'::jsonb, 2, '낮에는맑겠으나밤부터일부지역에는비가오겠다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 76, '불황에도포도주소비‘껑충’,불붙은판매경쟁', NULL, NULL, NULL, '["불황에도업체간경쟁때문에포도주의소비가늘었다.", "불황에도포도주판매감소때문에포도주의소비가줄었다.", "불황에도과도한판매경쟁때문에포도주의공급이증가했다.", "불황에도포도주소비증가때문에포도주의판매경쟁이심해졌다."]'::jsonb, 2, '불황에도포도주소비증가때문에포도주의판매경쟁이심해졌다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 77, '마을어르신들이‘지킴이’역할톡톡히,주민얼굴에웃음가득', NULL, NULL, NULL, '["노인들은마을주민들의도움에만족해하고있다.", "노인들은마을주민들의도움으로즐겁게일하고있다.", "주민들은안전을위해애쓰는마을노인들덕에기분이좋다.", "주민들은일을잘하려고노력하는노인들에게감사해하고있다."]'::jsonb, 2, '주민들은안전을위해애쓰는마을노인들덕에기분이좋다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 78, '동화는어린이가읽는책이라는인식이지배적이었다.그러나요즘은동화를통해()어른들이늘고있다.동화속이야기는지난기억과소중한것들을다시일깨워어른들을동심의세계로인도한다.이는나이가많든적든가난하든부유하든누구나공감할수있는이야기가동화속에존재하기때문에가능하다.', NULL, NULL, NULL, '["아이들을교육하려는", "어린시절을되돌아보려는", "가족사랑을확인해보려는", "아이를위한글을써보려는"]'::jsonb, 2, '어린시절을되돌아보려는', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 79, '훌륭한예술가는작품활동을하다가벽에부딪히면돌파구를찾아낸다.화가들에게()은‘독’이라기보다‘약’이었다.손이떨려그릴수없었던한화가는종이를잘라물감을칠해붙이는방법으로새로운작품세계를열었다.또가난해서그림재료를살수없었던어떤화가는담배포장지에스케치를했다.이런예술작품을통해자신만의예술세계를구축하였다.', NULL, NULL, NULL, '["재료의부족과호기심", "경제적빈곤과예술성", "신체적장애와열악한환경", "예술적한계와정신적고통"]'::jsonb, 2, '신체적장애와열악한환경', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 80, '지우개는다른문구류와오래닿으면그것에달라붙는성질이있다.지우개를만들때넣는특수한물질때문이다.지우개의재료인고무에약품을넣으면고무분자들이결합하게된다.그런데고무에넣은약품은플라스틱에들어가면()한다.이때문에지우개와플라스틱문구류를함께두면잘붙는다.', NULL, NULL, NULL, '["고무를달라붙게", "고무를딱딱하게", "문구류와붙지않게", "문구류에닿지않게"]'::jsonb, 2, '고무를달라붙게', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 81, '힙합은자아도취적인형식으로나타나기도하고집단적형태를취하기도한다.힙합은함께노래를부르고춤을추는사이에개인의아픔도서로격려하고위로하는()나타난다.희망을꿈꾼다는것이사치였던사람들에게힙합은서로의생각을주고받는몸짓이며외침이다.그들에게힙합은자신의존재가치를확인하게해주는의식과도같다.', NULL, NULL, NULL, '["형식적몸짓으로", "집단적의식으로", "다양한모습으로", "발전적인미래로"]'::jsonb, 2, '집단적의식으로', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 82, '보자기는물건을싸는실용적인용도로사용된다.그중에서쓰고남은천조각으로만든것을조각보라고한다.이조각보를만들때는쓰는사람이복을받기를바라는마음으로바느질을한다.이러한조각보가오늘날에는예술적으로도인정을받고있다.색도,모양도,크기도서로다른조각들을이어만든조각보에는자유분방한아름다움과조화로움이살아있기때문이다.', NULL, NULL, NULL, '["조각보는실용성보다예술성이강조되어있다.", "조각보는큰천을여러조각으로잘라서만들었다.", "조각보는색이같고모양이다른조각이이어져있다.", "조각보에는복을기원하는정성스러운마음이담겨있다."]'::jsonb, 2, '조각보에는복을기원하는정성스러운마음이담겨있다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 83, '조선시대에는역사를기록하는사관이있었다.왕의주변에서일어나는모든일을기록하는사관은누구의간섭도받지않았다.심지어왕이라도자신과관련된기록조차절대로볼수없었다.또한사관은기록에자신의이름을남기지않아정치적으로어떠한책임도지지않았다.조선에서사관의역할은왕이스스로자신의언행을조심하게하였고결과적으로그것은왕이권력을마음대로쓰지못하게하는장치로서기능을하였다.', NULL, NULL, NULL, '["역사를기록하는책에는사관의이름이적혀있었다.", "왕은필요할때사관의기록내용을찾아볼수있었다.", "사관의기록때문에왕은자신의언행을조심하게되었다.", "왕은주변에서일어나는모든일들을사관에게보고를받았다."]'::jsonb, 2, '사관의기록때문에왕은자신의언행을조심하게되었다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 84, '북극곰은고지방식사에빨리적응한동물이다.북극곰은몸의50%가지방이며새끼가먹는젖의지방도27%에이른다.사람이이만큼의지방을가지고있으면심혈관질환과같은성인병으로목숨을잃을수도있다.그러나북극곰은피속에지방을걸러내는유전자가있어지방으로인한부작용을막아주는것으로알려졌다.이동물의유전자를연구하면인간의성인병치료에도움이될것으로기대된다.', NULL, NULL, NULL, '["북극곰은심혈관질환에잘걸리지않는다.", "북극곰은지방이적은음식을주로섭취한다.", "북극곰의몸은27%가지방으로이루어져있다.", "북극곰연구로인간의성인병을치료하고있다.※[35～38]다음글의주제로가장알맞은것을고르십시오.(각2점)"]'::jsonb, 2, '북극곰은심혈관질환에잘걸리지않는다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 85, '메일을쓰거나문자메시지를주고받을때이모티콘을통해감정을표시한다.초창기문자나얼굴표정위주에서발전해만화인물을활용하여소리를내기도하고,움직임을더해웃음을유발하기도한다.1980년대초이모티콘이처음생긴이래끊임없이진화를계속하고있는것이다.언어표현력을퇴보시킨다는일부의비판에도불구하고이제이모티콘은없어서는안될또하나의언어로자리매김되었다고할수있다.', NULL, NULL, NULL, '["초창기이모티콘은대부분얼굴표정을나타내는것이었다.", "이모티콘은감정을표현하는또하나의언어로자리잡았다.", "이모티콘의지속적인사용은언어표현력을떨어뜨릴수있다.", "이제는이모티콘이없으면메시지를주고받기어려울정도이다."]'::jsonb, 2, '이모티콘은감정을표현하는또하나의언어로자리잡았다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 86, '어떤아이가자신이아끼는새에게온갖고기를먹이려했지만놀란새는한점의고기도먹지못하고죽었다는우화가있다.이는새의입장에서진정으로필요한것이무엇인지배려하지않아서생긴결과이다.그러나뭔가를배려할때먼저상대방의입장을고려해야한다는것은말처럼쉬운일이아니다.상대의입장을완벽하게이해하기란정말어렵기때문이다.따라서어설픈배려가오히려상대에게상처를줄수있다는깨달음이선행되어야한다.', NULL, NULL, NULL, '["상대를완벽하게이해하는것은사실상거의불가능하다.", "서투른배려는상대에게상처를줄수있음을알아야한다.", "우리는우화를통해진정한배려가무엇인지배울수있다.", "배려할때상대방의입장을고려하는것은큰의미가없다."]'::jsonb, 2, '서투른배려는상대에게상처를줄수있음을알아야한다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 87, '사람들은꿀이건강에좋은식품이라고생각한다.그래서꿀은당뇨병환자들에게도좋으며설탕과달리비만을일으키지않는다고생각한다.꿀에는영양소가풍부하지만혈당을높이기때문에당뇨병환자들에게설탕보다더나은것은결코아니다.우리가생각하는꿀의장점은대부분과학적으로증명되지않았다.꿀과설탕의결정적인차이는소비자의의식이지실제의장단점은아니다.', NULL, NULL, NULL, '["꿀은설탕보다건강에좋은대체식품이다.", "당뇨병환자는설탕대신에꿀을섭취해야한다.", "꿀에대해믿고있는장점이사실이아닐수있다.", "꿀이건강에미치는영향은과학적으로증명되었다."]'::jsonb, 2, '꿀에대해믿고있는장점이사실이아닐수있다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 88, '인터넷을사용하다보면자신의정보를제공하겠다는글에동의해야하는경우가많다.이와같이동의하는글을‘규약문’이라하는데여기에는사회적약속이나규정이있다.규약문은개인들사이의이해관계가엇갈려다툼이생길경우이를해결하는역할을한다.따라서인터넷으로소통하고자하는사람들은규약문을정확히파악하고그것이공정하고합리적인지평가해야한다.그래야자신의권리가부당하게침해받지않는다.', NULL, NULL, NULL, '["규약문의공정성에유의해서읽어야한다.", "규약문은정확한내용파악이가장중요하다.", "규약문의내용을정확히이해하고따져봐야한다.", "규약문을사용하기위해서는자신의정보를제공해야한다."]'::jsonb, 2, '규약문의내용을정확히이해하고따져봐야한다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 89, '인주상사가이번달부터‘자율근무제’를도입한다.(㉠)이제도는본인의업무시간을스스로정할수있어기존의출퇴근시간이사라지게된다.(㉡)이회사에서는오는10월까지모든사원을대상으로자율근무제를시범운영할예정이다.(㉢)시범운영기간이끝나면이제도의장점과단점을분석하고보완하여정식으로도입할예정이다.(㉣)다른기업들도이러한인주상사의자율근무제시행에큰관심을가지고있다.<보기>나아가이제도의도입을계기로조직문화의개선을위하여다양한유형의시도를계속할것이라고밝혔다.', NULL, NULL, NULL, '["㉠", "㉡", "㉢", "㉣"]'::jsonb, 2, '㉣', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 90, '(㉠)‘메디치효과’는서로관련없는분야가결합해전에없던창의적인결과를창출하는현상을말한다.(㉡)당시메디치가문은서로다른역량을가진예술가와학자들의공동작업을후원했다.그결과로피렌체지역의문화수준이한층높아졌다.(㉢)혁신적인기술과예술가의품격있는디자인이만나는사례는국내에서도찾아볼수있다.(㉣)그예로인주전자의최첨단기술과유럽의명품디자인사가공동출시한‘엔젤폰’이있다.<보기>이용어는르네상스의탄생과발전에큰역할을했던메디치라는가문의이름에서유래되었다.', NULL, NULL, NULL, '["㉠", "㉡", "㉢", "㉣"]'::jsonb, 2, '㉡', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 91, '정지우교수의영화,물리를말하다에서는영화속과학이야기를흥미진진하게보여준다.(㉠)물리학자인작가가과학의눈으로영화를들여다봄으로써그속에숨어있는과학을설명한다.(㉡)이책에서는영화에등장하는투명인간이나인공지능로봇등을다루고있다.(㉢)이책을통해과학의원리를이해하게된다면더욱흥미롭게영화를관람할수있을것이다.(㉣)또한과학이주는신비로운세상도경험할수있을것이다.<보기>이러한소재들은과학적지식을바탕으로인간의상상력을영화에구체화한것이다.', NULL, NULL, NULL, '["㉠", "㉡", "㉢", "㉣"]'::jsonb, 2, '㉢', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 41 ORDER BY created_at DESC LIMIT 1), 'reading', 92, '딴데랑은비교가안된다.모르긴해도세계에서제일맛있을것이다.이집은나름대로격조있는표현을동원해피자의미학을펼친다.종잇장처럼얄팍하지만바삭바삭하고도탄탄한빵반죽.그위에펼쳐지는절묘한맛의파노라마.큰피자,큰만족.소탈하면서도싹싹한여주인이메뉴판을가지고온다.내가시키는건정해져있다.아이들도마찬가지다.아무문제가없다.“자,뭘로하실까요?”연필을손에든채그녀가묻는다.“난,마르그리타로주세요.”“저두요.근데치즈는넣지마세요.”큰딸아이가말한다.“피자에다가치즈를안넣어요?”여주인은한방맞은기분인가보다.“왜요,불가능한가요?”딸애가꼬치꼬치따진다.“불가능한게아니라맛이없죠!”딱하다는말투다.(중략)작은딸은바질향소스를넣은파스타를주문한다.근데바질은넣지말란다.여주인이이상한눈으로나를흘깃쳐다본다.도대체내가애들을어떻게길렀기에이모양이지?치즈빼고,바질빼고,왜이렇게들삐딱할까.
밑줄친부분에나타난여주인의심정으로알맞은것을고르십시오.', NULL, NULL, NULL, '["난처하다", "황당하다", "서먹하다", "안타깝다"]'::jsonb, 2, '황당하다', NULL),
